import{c as o,Q as d,j as c,m as a}from"./chunks/framework.D9IbVcwA.js";const P=JSON.parse('{"title":"018-mm-address-space-1 · 地址空间","description":"","frontmatter":{"title":"018-mm-address-space-1 · 地址空间"},"headers":[],"relativePath":"tutorial/018-mm-address-space-1.md","filePath":"tutorial/018-mm-address-space-1.md","lastUpdated":1779686691000}'),t={name:"tutorial/018-mm-address-space-1.md"};function r(p,e,i,l,s,n){return d(),c("div",null,[...e[0]||(e[0]=[a('<h1 id="从一张页表到无数张-为什么进程需要独立的地址空间" tabindex="-1">从一张页表到无数张：为什么进程需要独立的地址空间 <a class="header-anchor" href="#从一张页表到无数张-为什么进程需要独立的地址空间" aria-label="Permalink to &quot;从一张页表到无数张：为什么进程需要独立的地址空间&quot;">​</a></h1><blockquote><p>标签：地址空间, PML4, 进程隔离, Higher Half, CR3 前置：<a href="./017-mm-heap-1">017-1 从页到字节：为什么内核需要堆分配器</a></p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>到目前为止，Cinux 的内存管理已经搭好了三层栈——PMM 管物理页，VMM 管虚拟映射， Heap 管任意大小的动态分配。听起来像是一切就绪了对吧？但你仔细想想会发现一个很 严重的问题：整个内核从头到尾只用了一张页表。CR3 寄存器在启动时被写入一次之后 就没再变过，所有代码、所有数据、所有动态分配出来的内存，全部共享同一套 PML4 -&gt; PDPT -&gt; PD -&gt; PT 的四级页表结构。</p><p>这种&quot;全世界只有一张页表&quot;的设计在单体内核阶段是完全合理的——反正就一个执行流 在跑，没有谁跟谁隔离的问题。可一旦我们想要&quot;进程&quot;这个概念，事情就完全不一样了。 进程的核心属性是什么？是隔离。进程 A 的内存不能被进程 B 看到，进程 B 的栈不能 被进程 A 踩到。如果两个进程共享同一张页表，进程 A 在虚拟地址 <code>0x400000</code> 写了个 数据，进程 B 在同一个地址也写了数据，它们就直接撞车了——因为在同一套页表里， 一个虚拟地址只能映射到一个物理页。</p><p>说实话，这个问题在操作系统课程里被讲过无数次了，每个教科书都会画那张经典的 &quot;每个进程有自己的页表&quot;的示意图。但当你真正坐下来写代码的时候，你会发现从&quot;知道 概念&quot;到&quot;把它变成一组可编译、可测试的数据结构&quot;之间有一大段距离。PML4 的 512 个 条目里哪些该复制、哪些该清零？析构的时候页表子树怎么递归释放才能不漏不重？ 两个 <code>AddressSpace</code> 能不能共享同一个物理 PML4（答案是不能，但为什么）？ 这些才是真正需要动手解决的问题。</p><p>tag 018 的目标就是在 VMM 之上再抽象一层——引入 <code>AddressSpace</code> 类，让每个进程 拥有自己独立的页表根（PML4），用户空间的映射互不可见，而内核空间的映射又保持 一致。整个 tag 涉及 10 个文件的变更，新增约 1470 行代码，核心是 <code>address_space.hpp</code>（144 行）和 <code>address_space.cpp</code>（198 行），另外还有 308 行 QEMU 集成测试和 771 行 Host 单元测试。</p><p>这一章我们先讨论&quot;为什么需要独立地址空间&quot;，把问题本身看清楚，然后研究 PML4 的 分割策略如何天然地适配了内核/用户的隔离需求，再对比 xv6 和 Linux 的经典设计， 最后看 Cinux 的 <code>AddressSpace</code> 类是如何被设计出来的。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-label="Permalink to &quot;环境说明&quot;">​</a></h2><p>本章涉及的核心文件是 <code>kernel/mm/address_space.hpp</code>（144 行）。运行环境和前面 几个 tag 一致——GCC cross-compiler（<code>x86_64-elf</code>）、QEMU、higher-half 内核 （<code>KERNEL_VMA = 0xFFFFFFFF80000000</code>）。前置条件是 PMM 和 VMM 已经初始化完毕， 因为 <code>AddressSpace</code> 的构造函数需要调用 <code>g_pmm.alloc_page()</code> 来分配新的 PML4 页。 在启动流程中，<code>init_kernel()</code> 被安排在 <code>kernel_main()</code> 的 Step 9，紧跟 VMM 初始化之后、Heap 初始化之前——时间窗口是确定的，VMM 就绪后内核页表已经完全建立 好了，此时读到的 CR3 就是&quot;标准内核页表&quot;的物理地址。</p><h2 id="问题-一个虚拟地址-多个进程-怎么办" tabindex="-1">问题：一个虚拟地址，多个进程，怎么办 <a class="header-anchor" href="#问题-一个虚拟地址-多个进程-怎么办" aria-label="Permalink to &quot;问题：一个虚拟地址，多个进程，怎么办&quot;">​</a></h2><p>我们先把这个问题的本质看清楚。x86-64 的四级分页机制下，CPU 做地址翻译时的起点 是 CR3 寄存器——它指向当前正在使用的 PML4 表的物理地址。根据 Intel SDM Vol.3A Section 4.5.2 的描述，CR3 的 bit 51:12 存放着 PML4 表的物理页帧号，4KB 对齐。 PML4 有 512 个条目，每个条目控制 512 GB 的虚拟地址空间，总共覆盖 256 TB 的 48 位规范地址空间。</p><p>当 CPU 需要访问虚拟地址 <code>0x20000000</code> 时，它先从 CR3 找到 PML4，取出条目索引 <code>(virt &gt;&gt; 39) &amp; 0x1FF</code>——对于 <code>0x20000000</code> 来说这个索引是 0，也就是第一个条目。 然后从这个条目找到 PDPT，再一路走到 PT，最终拿到物理地址。整个翻译过程是纯 硬件的，CPU 的 MMU 自动完成，每次内存访问都走这套流程。</p><p>现在假设内核创建了进程 A 和进程 B。进程 A 要在 <code>0x400000</code> 放自己的代码段， 进程 B 也要在 <code>0x400000</code> 放自己的代码段。如果两者共享同一张 PML4，那 <code>0x400000</code> 对应的 PTE 只能指向一个物理页——你不可能让同一个虚拟地址同时映射到两个不同的 物理页，同一张页表里一个条目只能存一个值。你可能会说&quot;那让进程 B 用另一个虚拟 地址不就行了&quot;——理论上确实可以，但这要求每个进程知道自己被分配了哪段虚拟地址 空间，编译器、链接器、动态加载器全部要配合，复杂度直接爆炸。更根本的问题是， 这违背了&quot;每个进程拥有独立地址空间&quot;的抽象——进程应该觉得自己独占整个地址空间， 从 <code>0x0</code> 到 <code>0xFFFFFFFFFFFFFFFF</code> 全是它自己的。</p><p>所以解法很自然：给每个进程一张独立的 PML4。进程 A 的 PML4 里，<code>0x400000</code> 映射到 物理页 X；进程 B 的 PML4 里，<code>0x400000</code> 映射到物理页 Y。切换进程时，把 CR3 从 A 的 PML4 换成 B 的 PML4，整个地址空间就切换了——后续所有的内存访问都走 B 的 页表，A 的映射对 B 完全不可见。这就是 Intel 硬件提供 CR3 寄存器的根本理由： 通过切换页表根来实现地址空间的隔离。</p><h2 id="pml4-的天然分割线-上半内核、下半用户" tabindex="-1">PML4 的天然分割线：上半内核、下半用户 <a class="header-anchor" href="#pml4-的天然分割线-上半内核、下半用户" aria-label="Permalink to &quot;PML4 的天然分割线：上半内核、下半用户&quot;">​</a></h2><p>搞清楚了&quot;需要多张 PML4&quot;之后，下一个问题是：每张 PML4 的 512 个条目是不是全部 独立？显然不是——内核代码和数据必须始终可见，否则中断处理、系统调用、驱动程序 全都不能工作。想象一下进程 A 正在执行，来了一个时钟中断，CPU trap 进内核态—— 此时如果内核的代码段和堆栈在 A 的 PML4 里没有映射，CPU 连中断处理函数的第一条 指令都取不到，直接 triple fault。</p><p>所以我们想要的效果是：PML4 的一部分（内核空间）在所有地址空间中完全一致，另一 部分（用户空间）各走各的。好在这个分割在 x86-64 的地址空间布局里是天然存在的。 根据 Intel SDM Vol.3A Section 4.5.4 的描述，48 位规范地址空间被分成两半： 下半部分从 <code>0x0000000000000000</code> 到 <code>0x00007FFFFFFFFFFF</code>（bit 47 为 0）， 上半部分从 <code>0xFFFF800000000000</code> 到 <code>0xFFFFFFFFFFFFFFFF</code>（bit 47 为 1，高 16 位 做符号扩展）。PML4 的条目索引是虚拟地址的 bit 47:39，所以条目 0 到 255 对应 下半部分（用户空间），条目 256 到 511 对应上半部分（内核空间）。每个 PML4 条目 控制一个 512 GB 的区域，所以用户空间最多 128 TB，内核空间也是最多 128 TB， 对任何操作系统来说都绰绰有余。</p><p>这意味着一个极其优雅的实现策略：构造新的 <code>AddressSpace</code> 时，分配一个新的 PML4 页， 把条目 0 到 255 全部清零（空白用户空间），然后把条目 256 到 511 从内核的 PML4 逐条复制过来（共享内核映射）。如此一来，每个地址空间的用户空间从零开始互相隔离， 内核空间则保持一致。而且这个复制操作非常轻量——只需要拷贝 256 个 8 字节的条目， 总共 2 KB 的数据，不需要递归拷贝 PDPT/PD/PT 这些下层页表。内核条目指向的 PDPT 页是共享的，所有地址空间通过相同的 PML4 条目值访问同一套内核页表结构。</p><p>这种设计模式在 OS 开发圈子里叫做 Higher Half Kernel——内核被映射到地址空间的 高半部分，所有进程共享；用户空间占据低半部分，每个进程独立。OSDev Wiki 的 <a href="https://wiki.osdev.org/Higher_Half_Kernel" target="_blank" rel="noreferrer">Higher Half Kernel</a> 页面对这种布局 有详细的描述，几乎所有现代 OS（Linux、Windows、macOS）都采用了这种模式。 Cinux 的 <code>KERNEL_VMA = 0xFFFFFFFF80000000</code> 也是基于这种布局——内核的虚拟地址 全在 <code>0xFFFF800000000000</code> 以上的区域。</p><h2 id="经典设计对比-xv6-与-linux" tabindex="-1">经典设计对比：xv6 与 Linux <a class="header-anchor" href="#经典设计对比-xv6-与-linux" aria-label="Permalink to &quot;经典设计对比：xv6 与 Linux&quot;">​</a></h2><p>在深入 Cinux 的实现之前，我们先看看两个经典 OS 是怎么处理&quot;每进程页表&quot;这个问题 的。对比是理解设计取舍的最好方式。</p><p>先看 xv6，MIT 的教学 OS（RISC-V 版本）。xv6 在 <code>kernel/proc.c</code> 的 <code>proc_pagetable()</code> 函数中创建进程页表。它调用 <code>uvmcreate()</code> 分配一个空白的 页表根——注意 xv6 跑在 RISC-V 上，用的是 Sv39 三级页表，所以它的页表根只有三层， 不像 x86-64 的四级。然后 xv6 通过 <code>mappages()</code> 把两个特殊页面映射到每个用户 页表中——trampoline 页存放 trap 入口代码，放在地址空间的最顶端（<code>MAXVA</code> 附近）， trapframe 页存放用户寄存器的保存区。这和 Cinux 复制 PML4[256..511] 的目的是 一样的——确保内核基础设施在每个地址空间中可见。</p><p>但 xv6 的做法有一个根本性的不同：它维护两套独立的页表——用户页表和内核全局 页表（<code>kernel_pagetable</code>）。从用户态 trap 进内核时，xv6 先把页表从用户页表切换 到 <code>kernel_pagetable</code>，在内核态运行期间一直使用这张全局页表，返回用户态之前再 切回用户页表。这种双页表设计的好处是内核页表不需要复制到每个用户页表里，节省了 内存——如果有 100 个进程，xv6 不需要复制 100 份内核页表条目。但代价是每次 trap 进出都要做一次页表切换，而且这种切换会导致 TLB 失效。另外，xv6 的双页表设计 还带来了一个著名的限制——内核无法直接通过用户虚拟地址访问用户内存（因为内核运行 在自己的页表上），必须通过 <code>copyin</code>/<code>copyout</code> 函数手动翻译。</p><p>再看 Linux。Linux 的做法和 Cinux 更像——内核映射存在于每个进程的页表中。 Linux 用 <code>mm_struct</code> 结构管理进程的地址空间，<code>task_struct-&gt;mm</code> 指向它。 <code>mm_struct-&gt;pgd</code> 保存着进程的 PGD（Page Global Directory，在 x86-64 上 PGD 就是 PML4）的物理地址。创建新进程时，<code>pgd_alloc()</code> 分配新的 PGD，然后通过 <code>pgd_ctor()</code> 把内核条目复制到 PGD 的对应位置——这和 Cinux 的构造函数逐条复制 PML4[256..511] 在逻辑上完全一致。进程切换时，<code>switch_mm()</code> 把新进程的 PGD 写入 CR3，和 Cinux 的 <code>activate()</code> 干的事情一模一样。</p><p>不过 Linux 的 <code>mm_struct</code> 比我们现在的 <code>AddressSpace</code> 复杂得多——它还包含 VMA 链表（<code>vm_area_struct</code>，描述每段连续虚拟内存区域的属性）、RSS 计数器（统计物理 内存使用量）、mmap 信号量（保护地址空间修改的并发安全）、缺页计数器等大量成员。 Cinux 的 <code>AddressSpace</code> 目前就是 Linux <code>mm_struct</code> 的最小子集——一个 PML4 物理 地址加上几个基本操作。VMA 管理、引用计数、COW fork 这些高级特性留给了后面的 tag。 Mel Gorman 在 <em>Understanding the Linux Virtual Memory Manager</em> 第 4 章中对 <code>mm_struct</code> 的结构和进程地址空间管理有详细的描述，如果你对 Linux 的完整实现 感兴趣，这是必读材料。</p><p>从 xv6 和 Linux 的对比中我们可以提炼出一个有意思的维度：xv6 选择&quot;内核页表独立 于用户页表&quot;来节省条目复制的开销，但付出了 trap 时页表切换的代价；Linux 选择 &quot;内核映射存在于每个用户页表&quot;来避免 trap 时的页表切换，但付出了一点复制开销和 内存占用。Cinux 选了 Linux 的路线——这在 x86-64 上是更自然的选择，因为 x86-64 的 syscall/sysret 指令对页表切换的支持不如 RISC-V 的 S 模式灵活，而且在同一张 页表里运行内核和用户代码，对 TLB 的利用率也更高。</p><h2 id="addressspace-类的设计概览" tabindex="-1">AddressSpace 类的设计概览 <a class="header-anchor" href="#addressspace-类的设计概览" aria-label="Permalink to &quot;AddressSpace 类的设计概览&quot;">​</a></h2><p>看完了对比，我们来看 Cinux 的类设计。<code>AddressSpace</code> 的公开接口非常精炼，但每一 个方法都有明确的职责和设计考量。</p><p>构造函数的核心逻辑是三步走：从 PMM 分配一个新的 4KB 物理页作为 PML4，把 512 个条目全部清零（这样用户空间从&quot;完全空白&quot;开始，所有虚拟地址访问都会触发 page fault），然后把内核 PML4 的条目 256 到 511 逐条复制过来。析构函数做的事情恰好 反过来——遍历用户空间条目 0 到 255，对每个 present 的条目递归释放整个页表子树 （PDPT -&gt; PD -&gt; PT），最后释放 PML4 页本身。<code>free_subtree</code> 在 PT 层级不再递归深入，但对 PT 条目仍然调用 <code>free_page</code>——这意味着 PT 条目指向的数据页也会被释放。在当前没有共享内存机制的设计中，每个 AddressSpace 独占其用户空间的物理页，析构时全量释放是最简单的策略。未来实现共享内存或 COW fork 时，需要改为引用计数管理数据页的生命周期。</p><p>拷贝构造和拷贝赋值被 <code>= delete</code> 禁止。这不是偷懒——而是安全性的硬要求。试想如果 允许拷贝构造，两个 <code>AddressSpace</code> 对象的 <code>pml4_phys_</code> 就指向同一个物理 PML4 页。 当第一个对象析构时，它把 PML4 归还给 PMM，第二个对象手里就剩下一个悬空指针， 后续任何操作都会往已经不属于自己的物理内存上写东西——这是经典的 use-after-free。 禁止拷贝从编译期就杜绝了这种可能性。移动语义是允许的——被移走的对象 <code>pml4_phys_</code> 置 0，析构时检查到 0 就跳过释放。这样 <code>AddressSpace</code> 就可以被放进容器里了。</p><p><code>init_kernel()</code> 是一个静态方法，整个类只有这一个&quot;启动钩子&quot;。它做的事情极其 简单——读 CR3，把值存到静态成员 <code>kernel_pml4_</code> 里。但它的调用时机非常关键：必须 在 bootloader 设置好内核页表之后、在创建第一个 <code>AddressSpace</code> 之前调用。为什么 不干脆在构造函数里直接读 CR3？因为构造函数读到的 CR3 是&quot;当前正在使用的&quot;页表根， 不一定是&quot;标准内核页表&quot;。如果进程 A 的 <code>AddressSpace</code> 被激活后 CR3 指向进程 A 的 PML4，此时再创建一个新的 <code>AddressSpace</code>，构造函数读到的就是 A 的 PML4 而不是 内核 PML4——复制出来的内核条目可能不是期望的。显式保存确保了模板来源是确定的、 一致的。</p><p><code>map()</code>、<code>unmap()</code>、<code>translate()</code> 三个方法是对 VMM 的直接委托。它们把 <code>&amp;pml4_phys_</code> 作为可选参数传给 <code>g_vmm</code> 的对应方法，让 VMM 知道&quot;用哪个 PML4 做 页表遍历的起点&quot;。这种设计让 <code>AddressSpace</code> 成了一个非常轻量的&quot;所有权包装器&quot;—— 页表遍历和修改的复杂逻辑全部复用 VMM 已有的实现。<code>activate()</code> 是唯一一个不委托 给 VMM 的操作——它直接调用 <code>write_cr3(pml4_phys_)</code>，用内联汇编把 PML4 物理地址 写入 CR3 寄存器。根据 Intel SDM Vol.3A Section 4.10.2 的规定，写入 CR3 会隐式 刷新所有非全局的 TLB 条目，所以切换地址空间后 CPU 的地址翻译缓存自动失效。</p><p>整个类的数据成员只有两个：实例成员 <code>pml4_phys_</code>（当前空间的 PML4 物理地址）和 静态成员 <code>kernel_pml4_</code>（启动时保存的内核 PML4 物理地址）。加起来 16 字节。 你可以把它类比为一张&quot;身份证&quot;——上面写着一个物理地址，凭借这个地址就能找到 一整套四级页表结构。<code>pml4_phys_</code> 是否为 0 是整个对象状态的&quot;哨兵&quot;：构造成功后 非 0，移动后变为 0，析构时也变为 0，所有生命周期操作都先检查它。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>到这里我们已经把&quot;为什么需要独立地址空间&quot;这个问题说清楚了——从单一张页表的 局限性，到 PML4 的自然分割如何优雅地适配了隔离需求，到 xv6 的双页表方案和 Linux 的共享映射方案的设计取舍，再到 Cinux <code>AddressSpace</code> 类的接口设计。 核心思想其实很简单：每个进程一张 PML4，上半复制内核映射，下半各管各的。</p><p>但设计概览只是图纸，真正的乐趣在实现细节里。下一章我们深入构造函数和析构函数 的代码，看看&quot;分配 PML4 -&gt; 清零 -&gt; 复制内核条目&quot;这三步在代码里是怎么走的， 析构时递归释放页表子树的 <code>free_subtree</code> 是如何保证不漏不重的，以及 move 语义 在&quot;独占所有权&quot;的约束下是如何安全转移的。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM Vol.3A Section 4.5.2, pp.4-20 to 4-21：CR3 寄存器格式，PML4 物理基地址 在 CR3 中的位置，<code>init_kernel()</code> 和 <code>activate()</code> 的硬件基础。</li><li>Intel SDM Vol.3A Section 4.5.4, pp.4-22 to 4-25：四级分页的完整地址翻译流程， PML4 条目索引与虚拟地址位域的对应关系。</li><li>Intel SDM Vol.3A Section 4.10.2：CR3 写入对 TLB 的影响，<code>activate()</code> 隐式 TLB 刷新的硬件机制。</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Higher_Half_Kernel" target="_blank" rel="noreferrer">Higher Half Kernel</a> — 内核映射到地址空间高半部分的设计模式，Cinux PML4 分割策略的来源。</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Paging" target="_blank" rel="noreferrer">Paging</a> — 四级分页结构详解， 512 条目表、CR3 格式、PTE 格式。</li><li>xv6 RISC-V <code>proc.c</code>: <a href="https://github.com/mit-pdos/xv6-riscv/blob/riscv/kernel/proc.c" target="_blank" rel="noreferrer">GitHub</a> — <code>proc_pagetable()</code> 创建进程页表的逻辑，双页表设计。</li><li>xv6 RISC-V <code>vm.c</code>: <a href="https://github.com/mit-pdos/xv6-riscv/blob/riscv/kernel/vm.c" target="_blank" rel="noreferrer">GitHub</a> — <code>uvmcreate()</code>、<code>uvmfree()</code>、<code>uvmcopy()</code> 的实现。</li><li>Linux <code>mm_struct</code>: <a href="https://www.kernel.org/doc/html/next/mm/process_addrs.html" target="_blank" rel="noreferrer">kernel.org 文档</a> — 进程地址空间管理，<code>pgd_alloc()</code> 复制内核条目的设计。</li><li>Mel Gorman, <em>Understanding the Linux Virtual Memory Manager</em>, Chapter 4： <code>mm_struct</code> 的完整结构和进程地址空间管理机制。</li></ul>',39)])])}const m=o(t,[["render",r]]);export{P as __pageData,m as default};
